This page is reserved for employees of Pine Straw Distributors LLC only.
Unauthorized access is prohibited.


&lt;h4&gt;Employee Login&lt;/h4&gt;
&lt;p class="portal-sub"&gt;Sign in to access the employee portal.&lt;/p&gt;

&lt;form&gt;
  &lt;div class="mb-3"&gt;
    &lt;label for="username" class="form-label"&gt;Username&lt;/label&gt;
    &lt;input type="text" class="form-control" id="username" placeholder="Enter username"&gt;
  &lt;/div&gt;
  &lt;div class="mb-3"&gt;
    &lt;label for="password" class="form-label"&gt;Password&lt;/label&gt;
    &lt;input type="password" class="form-control" id="password" placeholder="Enter password"&gt;
  &lt;/div&gt;
  &lt;button type="submit" class="btn btn-success w-100"&gt;Sign In&lt;/button&gt;
&lt;/form&gt;


&lt;h5&gt;Portal Contents&lt;/h5&gt;
&lt;ul&gt;
  &lt;li&gt;&lt;i class="bi bi-file-earmark-text"&gt;&lt;/i&gt; Employee Manual&lt;/li&gt;
  &lt;li&gt;&lt;i class="bi bi-heart-pulse"&gt;&lt;/i&gt; Benefits Packages&lt;/li&gt;
  &lt;li&gt;&lt;i class="bi bi-calendar-check"&gt;&lt;/i&gt; Time & Attendance&lt;/li&gt;
  &lt;li&gt;&lt;i class="bi bi-cash-stack"&gt;&lt;/i&gt; Payroll Information&lt;/li&gt;
  &lt;li&gt;&lt;i class="bi bi-geo-alt"&gt;&lt;/i&gt; Delivery Schedules&lt;/li&gt;
  &lt;li&gt;&lt;i class="bi bi-envelope"&gt;&lt;/i&gt; Company Directory&lt;/li&gt;
&lt;/ul&gt;
